import sys

class TreeNode:
    def __init__(self, x):
        self.val = x
        self.left = None
        self.right = None

class Solution:
    def isSymmetric(self, root: TreeNode) -> bool:
        if root is None:
            return True
        return self.isMirror(root.left, root.right)

    def isMirror(self, left, right):
        if left is None and right is None:
            return True
        if left is None or right is None:
            return False
        return (left.val == right.val) and self.isMirror(left.right, right.left) and self.isMirror(left.left, right.right)

if __name__ == '__main__':
    n = int(sys.stdin.readline().strip())
    nodes = []
    for _ in range(n):
        nodes.append(int(sys.stdin.readline().strip()))
    root = TreeNode(nodes[0])
    nodeList = [root]
    i = 1
    while i < n:
        currentNode = nodeList.pop(0)
        leftVal = nodes[i]
        i += 1
        if leftVal != -1:
            currentNode.left = TreeNode(leftVal)
            nodeList.append(currentNode.left)
        if i < n:
            rightVal = nodes[i]
            i += 1
            if rightVal != -1:
                currentNode.right = TreeNode(rightVal)
                nodeList.append(currentNode.right)
    sol = Solution()
    print(1 if sol.isSymmetric(root) else 0)

