#include <numeric>
#include <iostream>
#include <vector>
using namespace std;

struct TreeNode {
    int val;
    TreeNode *left;
    TreeNode *right;
    TreeNode(int x) : val(x), left(NULL), right(NULL) {}
};

class Solution {
public:
    bool isSymmetric(TreeNode* root) {
        if (root == NULL) return true;
        return isMirror(root->left, root->right);
    }

    bool isMirror(TreeNode* left, TreeNode* right) {
        if (left == NULL && right == NULL) return true;
        if (left == NULL || right == NULL) return false;
        return (left->val == right->val) && isMirror(left->right, right->left) && isMirror(left->left, right->right);
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int n;
    cin >> n;
    vector<int> nodes(n);
    for (int i = 0; i < n; i++) cin >> nodes[i];
    TreeNode* root = new TreeNode(nodes[0]);
    vector<TreeNode*> nodeList = {root};
    int i = 1;
    while (i < n) {
        TreeNode* currentNode = nodeList.front();
        nodeList.erase(nodeList.begin());
        int leftVal = nodes[i++];
        if (leftVal != -1) {
            currentNode->left = new TreeNode(leftVal);
            nodeList.push_back(currentNode->left);
        }
        if (i < n) {
            int rightVal = nodes[i++];
            if (rightVal != -1) {
                currentNode->right = new TreeNode(rightVal);
                nodeList.push_back(currentNode->right);
            }
        }
    }
    Solution sol;
    cout << (sol.isSymmetric(root) ? 1 : 0) << endl;
    return 0;
}
